function parseSender(input, fromObj) {
  let senderName = '';
  let senderEmail = '';

  if (fromObj && typeof fromObj === 'object') {
    if (typeof fromObj.text === 'string' && fromObj.text.trim()) input = fromObj.text;
    if (Array.isArray(fromObj.value) && fromObj.value[0]) {
      senderName = (fromObj.value[0].name || '').trim();
      senderEmail = (fromObj.value[0].address || '').trim();
    }
    if (!senderEmail && typeof fromObj.address === 'string') senderEmail = fromObj.address.trim();
    if (!senderName && typeof fromObj.name === 'string') senderName = fromObj.name.trim();
  }

  const raw = (input || '').toString().trim();
  if (!senderEmail && raw) {
    const angle = raw.match(/(.*)<([^>]+)>/);
    if (angle) {
      senderName = senderName || angle[1].replace(/\"/g, '').trim();
      senderEmail = angle[2].trim();
    }
  }

  if (!senderEmail && raw) {
    const plainMail = raw.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
    if (plainMail) senderEmail = plainMail[0].trim();
  }

  if (!senderName && raw) senderName = raw.replace(/<[^>]+>/g, '').replace(/[\"']/g, '').trim();
  if (!senderName) senderName = senderEmail || 'Unknown Sender';
  if (!senderEmail) senderEmail = 'unknown@example.local';

  return { senderName, senderEmail };
}

function decodeQuotedPrintable(text) {
  let s = (text || '').toString();
  s = s.replace(/=\r?\n/g, '');
  s = s.replace(/=([A-Fa-f0-9]{2})/g, (_, hex) => {
    const code = Number.parseInt(hex, 16);
    return Number.isNaN(code) ? '' : String.fromCharCode(code);
  });
  return s;
}

function toPlainText(input) {
  return decodeQuotedPrintable(input || '')
    .replace(/<br\s*\/?\s*>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<\/li>/gi, '\n')
    .replace(/<li[^>]*>/gi, '- ')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/[\t ]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function parseStructuredFields(text) {
  const fields = {
    title: '',
    description: '',
    dueDateRaw: '',
    priorityRaw: '',
    assignedRaw: '',
    categoryRaw: '',
    subtasksRaw: '',
    statusRaw: ''
  };

  const source = (text || '').toString();
  if (!source) return fields;

  const keyMap = {
    title: 'title',
    titel: 'title',
    description: 'description',
    descritpion: 'description',
    'due date': 'dueDateRaw',
    duedate: 'dueDateRaw',
    due: 'dueDateRaw',
    priority: 'priorityRaw',
    prio: 'priorityRaw',
    assigned: 'assignedRaw',
    assign: 'assignedRaw',
    category: 'categoryRaw',
    catgory: 'categoryRaw',
    categroy: 'categoryRaw',
    subtask: 'subtasksRaw',
    subtasks: 'subtasksRaw',
    status: 'statusRaw'
  };

  const regex = /(title|titel|description|descritpion|due\s*date|duedate|due|priority|prio|assigned|assign|category|catgory|categroy|subtasks?|status)\s*:/ig;
  const hits = [];
  let m;
  while ((m = regex.exec(source)) !== null) {
    hits.push({
      label: m[1].toLowerCase().replace(/\s+/g, ' ').trim(),
      index: m.index,
      end: regex.lastIndex
    });
  }

  for (let i = 0; i < hits.length; i++) {
    const cur = hits[i];
    const next = hits[i + 1];
    const rawValue = source.slice(cur.end, next ? next.index : source.length).trim();
    const key = keyMap[cur.label];
    if (key && rawValue) fields[key] = rawValue;
  }

  return fields;
}

function normalizeDueDate(input) {
  const raw = (input || '').toString().trim();
  if (!raw) {
    const d = new Date();
    d.setDate(d.getDate() + 1);
    return d.toISOString().slice(0, 10);
  }

  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;

  const m = raw.match(/^(\d{1,2})[.\/-](\d{1,2})[.\/-](\d{2}|\d{4})$/);
  if (m) {
    const dd = m[1].padStart(2, '0');
    const mm = m[2].padStart(2, '0');
    let yy = m[3];
    if (yy.length === 2) yy = (Number(yy) >= 70 ? '19' : '20') + yy;
    return `${yy}-${mm}-${dd}`;
  }

  const parsed = new Date(raw);
  if (!Number.isNaN(parsed.getTime())) return parsed.toISOString().slice(0, 10);

  const d = new Date();
  d.setDate(d.getDate() + 1);
  return d.toISOString().slice(0, 10);
}

function normalizePriority(input) {
  const p = (input || '').toString().toLowerCase().trim();
  if (p.includes('urgent') || p.includes('high') || p.includes('highest') || p.includes('critical') || p.includes('hoch')) return 'high';
  if (p.includes('low') || p.includes('niedrig')) return 'low';
  return 'medium';
}

function normalizeCategory(input) {
  const c = (input || '').toString().toLowerCase().trim();
  if (c.includes('tech') || c.includes('technical') || c.includes('engineering') || c.includes('dev')) return 'tech';
  return 'user';
}

function normalizeStatus(input) {
  const s = (input || '').toString().toLowerCase().trim();
  if (s.includes('progress')) return 'progress';
  if (s.includes('feedback') || s.includes('review')) return 'feedback';
  if (s.includes('done') || s.includes('finish')) return 'done';
  return 'todo';
}

function parseAssigned(input) {
  return (input || '')
    .toString()
    .split(/[;,\n]/)
    .map((v) => v.trim())
    .filter(Boolean);
}

function parseSubtasks(input) {
  const parts = (input || '')
    .toString()
    .split(/\n|;|\.{3,}|,/)
    .map((v) => v.replace(/^[-*]\s*/, '').trim())
    .filter(Boolean);
  return parts.map((title) => ({ title, done: false }));
}

const subject = ($json.subject || 'Email Request').toString().trim();
const messageIdRaw = ($json.messageId || $json['message-id'] || ($json.headers && $json.headers['message-id']) || $json.id || ('mail_' + Date.now())).toString();
const receivedAt = ($json.date || ($json.headers && $json.headers.date) || new Date().toISOString()).toString();
const sender = parseSender(($json.headers && $json.headers.from) || $json.from || '', $json.from);
const bodyText = toPlainText($json.textPlain || $json.text || $json.textHtml || $json.html || '');
const fields = parseStructuredFields(bodyText);
const todayIso = new Date().toISOString().slice(0, 10);

const taskId = String(Date.now());
const messageKey = messageIdRaw
  .toLowerCase()
  .replace(/[.#$/\[\]]/g, '_')
  .replace(/[^a-z0-9_-]/g, '_')
  .slice(0, 120);

const prompt = [
  'You are an email-to-task extraction agent.',
  'Read the email and return ONLY valid JSON (no markdown, no explanation).',
  'JSON schema (all string values):',
  '{"title":"","description":"","dueDateRaw":"","priorityRaw":"","assignedRaw":"","categoryRaw":"","subtasksRaw":"","statusRaw":""}',
  'Extraction rules:',
  '- title: short, actionable task title.',
  '- description: concise but complete summary of request.',
  '- dueDateRaw: ISO date YYYY-MM-DD if date can be inferred, otherwise empty string.',
  '- If text says things like "by August 2nd latest", convert to YYYY-MM-DD.',
  '- priorityRaw: high|medium|low (high if text says highest priority / priority over everything else).',
  '- assignedRaw: comma-separated names, empty if unknown.',
  '- categoryRaw: tech or user (tech for implementation/development/infrastructure tasks).',
  '- subtasksRaw: semicolon-separated list of concrete subtasks.',
  '- statusRaw: todo|progress|feedback|done (default todo).',
  '',
  `Today: ${todayIso}`,
  `From: ${sender.senderName} <${sender.senderEmail}>`,
  `Subject: ${subject}`,
  '',
  'Body:',
  bodyText || '(empty)'
].join('\n');

return [{
  json: {
    taskId,
    messageKey,
    messageIdRaw,
    prompt,
    senderName: sender.senderName,
    senderEmail: sender.senderEmail,
    receivedAt,
    subject,
    bodyText,
    parsedFields: fields,
    task: {
      id: taskId,
      title: (fields.title || subject || ('Email Request - ' + sender.senderName)).slice(0, 80),
      description: (fields.description || bodyText || '').slice(0, 4000),
      dueDate: normalizeDueDate(fields.dueDateRaw),
      category: normalizeCategory(fields.categoryRaw),
      priority: normalizePriority(fields.priorityRaw),
      status: normalizeStatus(fields.statusRaw),
      subtasks: parseSubtasks(fields.subtasksRaw),
      assigned: parseAssigned(fields.assignedRaw),
      source: 'email',
      requester: sender.senderName,
      requesterEmail: sender.senderEmail,
      receivedAt
    }
  }
}];

function normalizeDueDate(input) {
  const raw = String(input || '').trim();
  if (!raw) return new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
  if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;

  const match = raw.match(/^(\d{1,2})[.\/-](\d{1,2})[.\/-](\d{2}|\d{4})$/);
  if (match) {
    const dd = match[1].padStart(2, '0');
    const mm = match[2].padStart(2, '0');
    let yy = match[3];
    if (yy.length === 2) yy = (Number(yy) >= 70 ? '19' : '20') + yy;
    return `${yy}-${mm}-${dd}`;
  }

  const parsed = new Date(raw);
  if (!Number.isNaN(parsed.getTime())) return parsed.toISOString().slice(0, 10);

  return new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
}

function normalizePriority(input) {
  const value = String(input || '').toLowerCase().trim();
  if (value.includes('urgent') || value.includes('high') || value.includes('highest') || value.includes('critical') || value.includes('hoch')) return 'high';
  if (value.includes('low') || value.includes('niedrig')) return 'low';
  return 'medium';
}

function normalizeCategory(input) {
  const value = String(input || '').toLowerCase().trim();
  if (value.includes('tech') || value.includes('technical') || value.includes('engineering') || value.includes('dev')) return 'tech';
  return 'user';
}

function normalizeStatus(input) {
  const value = String(input || '').toLowerCase().trim();
  if (value.includes('progress')) return 'progress';
  if (value.includes('feedback') || value.includes('review')) return 'feedback';
  if (value.includes('done') || value.includes('finish')) return 'done';
  return 'todo';
}

function parseAssigned(input) {
  return String(input || '')
    .split(/[;,\n]/)
    .map((value) => value.trim())
    .filter(Boolean);
}

function parseSubtasks(input) {
  return String(input || '')
    .split(/\n|;|\.{3,}|,/)
    .map((value) => value.replace(/^[-*]\s*/, '').trim())
    .filter(Boolean)
    .map((title) => ({ title, done: false }));
}

function parseJsonLoose(input) {
  if (input == null) return {};
  if (typeof input === 'object') return input;
  const text = String(input).trim();
  if (!text) return {};

  try {
    return JSON.parse(text);
  } catch {}

  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)\s*```/i);
  if (fenced && fenced[1]) {
    try {
      return JSON.parse(fenced[1]);
    } catch {}
  }

  const first = text.indexOf('{');
  const last = text.lastIndexOf('}');
  if (first !== -1 && last > first) {
    const candidate = text.slice(first, last + 1);
    try {
      return JSON.parse(candidate);
    } catch {}
  }

  return {};
}

const context = $('Build Task Payload').item.json;
const rawOutput =
  $json.output ??
  $json.response ??
  $json.content ??
  ($json.message && $json.message.content) ??
  ($json.data && $json.data.output) ??
  $json;

const extracted = parseJsonLoose(rawOutput);

const sourceTask = context.task || {};
const title = String(extracted.title || sourceTask.title || context.subject || 'Task').trim();
const description = String(extracted.description || sourceTask.description || context.bodyText || '').trim();

return [{
  json: {
    taskId: context.taskId,
    messageKey: context.messageKey,
    messageIdRaw: context.messageIdRaw,
    senderName: context.senderName,
    senderEmail: context.senderEmail,
    parsedFields: extracted,
    task: {
      id: context.taskId,
      title,
      description,
      dueDate: normalizeDueDate(extracted.dueDateRaw),
      category: normalizeCategory(extracted.categoryRaw),
      priority: normalizePriority(extracted.priorityRaw),
      status: normalizeStatus(extracted.statusRaw),
      subtasks: parseSubtasks(extracted.subtasksRaw),
      assigned: parseAssigned(extracted.assignedRaw),
      source: 'email',
      requester: context.senderName,
      requesterEmail: context.senderEmail,
      receivedAt: context.receivedAt,
    },
  },
}];

const raw = $json;
let count = 0;

if (raw == null) {
  count = 0;
} else if (typeof raw === 'number') {
  count = raw;
} else if (typeof raw === 'string' && raw.trim() !== '') {
  const asNum = Number(raw);
  count = Number.isFinite(asNum) ? asNum : 0;
} else if (raw && typeof raw === 'object') {
  if (typeof raw.count === 'number') count = raw.count;
  else if (typeof raw.value === 'number') count = raw.value;
  else if (typeof raw.data === 'number') count = raw.data;
  else if (typeof raw.body === 'number') count = raw.body;
  else {
    const values = Object.values(raw);
    if (values.length === 1 && typeof values[0] === 'number') count = values[0];
  }
}

count = Number.isFinite(count) ? Math.max(0, Math.floor(count)) : 0;
const limit = 10;
const allowed = count < limit;
return [{ json: { day: $now.setZone('Europe/Berlin').toISODate(), count, nextCount: count + 1, limit, allowed } }];
